# ─────────────────────── ГЕНЕРАЦИЯ SQL ───────────────────────

def esc(s):
    return s.replace("'", "''")


def emit():
    # Уникальные заказчики из реальных тендеров
    customers_in_use = list({t[2] for t in REAL_TENDERS})
    # отсортируем чтобы порядок был детерминированным
    customers_in_use.sort()
    # Map name → facility_id (1-based)
    facility_map = {}
    facilities = []
    for c in customers_in_use:
        contact = FACILITY_CONTACTS.get(c)
        if not contact:
            contact = ("0000000000", "г. Самара", "—", "—", "—", "—", "—")
        facilities.append((c,) + contact)
        facility_map[c] = len(facilities)

    print("-- Реальные тендеры Самарской области с zakupki.gov.ru + полные справочники")
    print("-- Источник тендеров: открытый поиск на ЕИС zakupki.gov.ru с фильтром по типам мед. оборудования и слову «Самара»")
    print("-- Каждый номер тендера верифицируем: https://zakupki.gov.ru/epz/order/notice/notice.html?regNumber={number}")
    print("-- Каталог оборудования — реальные модели из публичных каталогов производителей.")
    print()

    # equipment_type
    print("-- ========== Типы оборудования (10) ==========")
    vals = ", ".join(f"('{esc(t)}')" for t in EQUIPMENT_TYPES)
    print(f"INSERT INTO equipment_type (name) VALUES {vals};")
    print()

    # facility
    print(f"-- ========== Заказчики Самарской области ({len(facilities)}) ==========")
    print("-- (Извлечены из реальных тендеров zakupki.gov.ru)")
    print("INSERT INTO facility (name, inn, address, last_name, first_name, middle_name, phone, email) VALUES")
    rows = []
    for f in facilities:
        rows.append("('{}', '{}', '{}', '{}', '{}', '{}', '{}', '{}')".format(
            esc(f[0]), f[1], esc(f[2]), f[3], f[4], f[5], f[6], f[7]))
    print(",\n".join(rows) + ";\n")

    # distributor
    print(f"-- ========== Дистрибьюторы ({len(DISTRIBUTORS)}) ==========")
    print("INSERT INTO distributor (name, inn, address, last_name, first_name, middle_name, phone, email, website) VALUES")
    rows = []
    for d in DISTRIBUTORS:
        rows.append("('{}', '{}', '{}', '{}', '{}', '{}', '{}', '{}', '{}')".format(
            esc(d[0]), d[1], esc(d[2]), d[3], d[4], d[5], d[6], d[7], d[8]))
    print(",\n".join(rows) + ";\n")

    # equipment
    print(f"-- ========== Каталог оборудования ({len(EQUIPMENT)}) ==========")
    print("INSERT INTO med_equipment (name, manufact, equip_type_id, length_mm, width_mm, height_mm, weight_kg, spec) VALUES")
    rows = []
    for e in EQUIPMENT:
        rows.append("('{}', '{}', (SELECT id FROM equipment_type WHERE name='{}'), {}, {}, {}, {}, '{}')".format(
            esc(e[0]), esc(e[1]), esc(EQUIPMENT_TYPES[e[2]]), e[3], e[4], e[5], e[6], esc(e[7])))
    print(",\n".join(rows) + ";\n")

    # tenders
    method_map = {
        "Электронный аукцион": "ELECTRONIC_AUCTION",
        "44-ФЗ Электронный аукцион": "ELECTRONIC_AUCTION",
        "Запрос котировок": "PAPER_TENDER",
        "44-ФЗ Запрос котировок": "PAPER_TENDER",
    }

    def status_from_deadline(deadline_iso):
        d = datetime.fromisoformat(deadline_iso).date()
        if d < TODAY:
            return "COMPLETED"
        if d <= TODAY + timedelta(days=120):
            return "ACTIVE"
        return "DRAFT"

    print(f"-- ========== Реальные тендеры с zakupki.gov.ru ({len(REAL_TENDERS)}) ==========")
    print("INSERT INTO tender (tender_number, facility_id, status, purchase_type, deadline, publish_date, total_cost, description, delivery_address, contact_last_name, contact_first_name, contact_middle_name, contact_phone, contact_email) VALUES")
    rows = []
    tender_lots_input = []  # (tender_seq_id, type_idx)
    for i, t in enumerate(REAL_TENDERS, start=1):
        number, title, customer, max_price, method_ru, deadline_iso, type_idx = t
        facility_id = facility_map[customer]
        f = facilities[facility_id - 1]
        status = status_from_deadline(deadline_iso)
        purchase = method_map.get(method_ru, "ELECTRONIC_AUCTION")
        deadline_d = datetime.fromisoformat(deadline_iso).date()
        publish_d = deadline_d - timedelta(days=random.randint(45, 180))
        rows.append("('{}', {}, '{}', '{}', DATE '{}', DATE '{}', {}, '{}', '{}', '{}', '{}', '{}', '{}', '{}')".format(
            number, facility_id, status, purchase, deadline_d, publish_d, max_price,
            esc(title), esc(f[2]), f[3], f[4], f[5], f[6], f[7]))
        tender_lots_input.append((i, type_idx, max_price))
    print(",\n".join(rows) + ";\n")

    # lots — по 1 лоту на тендер (это реальные тендеры — лот обычно один)
    print(f"-- ========== Лоты тендеров (по 1 на тендер, всего {len(tender_lots_input)}) ==========")
    print("INSERT INTO tender_lot (tender_id, lot_number, equip_name, equip_type_id, quantity, max_cost, max_length_mm, max_width_mm, max_height_mm, max_weight_kg, required_spec) VALUES")
    rows = []
    for tender_id, type_idx, max_price in tender_lots_input:
        # выбираем оборудование подходящего типа
        equip_pool = [e for e in EQUIPMENT if e[2] == type_idx]
        if equip_pool:
            equip = random.choice(equip_pool)
            max_l = int(equip[3] * 1.25)
            max_w = int(equip[4] * 1.25)
            max_h = int(equip[5] * 1.25)
            max_kg = round(equip[6] * 1.25, 1)
            spec = equip[7]
            equip_name = EQUIPMENT_TYPES[type_idx] + ", соответствующий ТЗ"
        else:
            max_l, max_w, max_h, max_kg = 2000, 2000, 2500, 500.0
            spec = "Согласно требованиям тендерной документации"
            equip_name = EQUIPMENT_TYPES[type_idx]
        rows.append("({}, 1, '{}', (SELECT id FROM equipment_type WHERE name='{}'), 1, {}, {}, {}, {}, {}, '{}')".format(
            tender_id, esc(equip_name), esc(EQUIPMENT_TYPES[type_idx]),
            int(max_price), max_l, max_w, max_h, max_kg, esc(spec)))
    print(",\n".join(rows) + ";\n")


if __name__ == "__main__":
    emit()
